          <Value>#{escape_xml(result.value)}</Value>
          <Status>OK</Status>
        </Response>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp soap_fault(code, message) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{escape_xml(code)}</faultcode>
          <faultstring>#{escape_xml(message)}</faultstring>
        </soap:Fault>
